import {
    PIECE_COLOR_BLACK,
    PIECE_COLOR_WHITE,
    PIECE_TYPE_NEANG,
    PIECE_TYPE_SDECH,
    boardHelper,
} from './index';
import {
    Piece,
    PieceIndex,
    Point,
} from '../ren/index';

type OptionsType = {
    piecesString: string;
    currentTurn: string;
    isNeangMoved: boolean;
    isSdechMoved: boolean;
    genCanMove: boolean;
    genCanMoveForAnother: boolean;
};
type CalCountPropsType = {
    piecesString: string;
    force: boolean;
};
class MoveHelper {
    piecesString: string;
    currentTurn: string;
    isNeangMoved: boolean;
    isSdechMoved: boolean;
    genCanMove: boolean;
    genCanMoveForAnother: boolean;
    whiteMoves: PieceIndex[];
    blackMoves: PieceIndex[];
    whiteKingInDanger: Point[] | null;
    whiteKingWillInDanger: Point[] | null;
    blackKingInDanger: Point[] | null;
    blackKingWillInDanger: Point[] | null;
    winColor: string | null;
    stuckColor: string | null;
    init(option: OptionsType) {
        this.piecesString = option.piecesString;
        this.currentTurn = option.currentTurn;
        this.isNeangMoved = option.isNeangMoved;
        this.isSdechMoved = option.isSdechMoved;

        this.genCanMove = option.genCanMove;
        this.genCanMoveForAnother = option.genCanMoveForAnother;

        this.whiteMoves = [];
        this.blackMoves = [];

        this.whiteKingInDanger = null;
        this.whiteKingWillInDanger = null;
        this.blackKingInDanger = null;
        this.blackKingWillInDanger = null;

        this.winColor = null;
        this.stuckColor = null;
    }

    generateCanMoves() {
        const filter = boardHelper.filterPieceInBoard(this.piecesString);
        this.whiteMoves = filter.whitePieces;
        this.blackMoves = filter.blackPieces;
        const genMoves = (pieces: string | any[]) => {
            for (let i = 0; i < pieces.length; i++) {
                const piece = pieces[i];
                const type = piece.type;
                const isSdech = type === PIECE_TYPE_SDECH;
                const isNeang = type === PIECE_TYPE_NEANG;
                let isHaveMoved = this.isSdechMoved;
                if (!isSdech) {
                    isHaveMoved = isNeang ? this.isNeangMoved : false;
                }
                const canMoveIndexes = boardHelper.generatePosesCanMove(
                    piece.index,
                    piece,
                    this.piecesString,
                    isHaveMoved
                );
                piece.canMoveIndexes = canMoveIndexes;
            }
        };
        genMoves(this.whiteMoves);
        genMoves(this.blackMoves);
    }

    cleanPieceNoMove() {
        const cleanMoves = (pieces: any[]) => {
            let isTrue = true;
            while (isTrue) {
                isTrue = false;
                for (let i = 0; i < pieces.length; i++) {
                    const piece = pieces[i];
                    if (!piece.canMoveIndexes || !piece.canMoveIndexes.length) {
                        pieces.splice(i, 1);
                        isTrue = true;
                        break;
                    }
                }
            }
        };
        cleanMoves(this.whiteMoves);
        cleanMoves(this.blackMoves);
    }

    checkIfKingInDanger() {
        this.whiteKingInDanger = boardHelper.getKingInDanger(
            PIECE_COLOR_WHITE,
            this.piecesString
        );
        this.whiteKingWillInDanger = boardHelper.getKingWillInDanger(
            PIECE_COLOR_WHITE,
            this.piecesString
        );
        this.blackKingInDanger = boardHelper.getKingInDanger(
            PIECE_COLOR_BLACK,
            this.piecesString
        );
        this.blackKingWillInDanger = boardHelper.getKingWillInDanger(
            PIECE_COLOR_BLACK,
            this.piecesString
        );
    }

    genWinLost() {
        if (this.whiteKingInDanger && !this.whiteMoves.length) {
            this.winColor = PIECE_COLOR_BLACK;
        } else if (this.blackKingInDanger && !this.blackMoves.length) {
            this.winColor = PIECE_COLOR_WHITE;
        }
    }

    getStuck() {
        if (this.winColor) {
            return;
        }
        if (Piece.isWhiteColor(this.currentTurn) && !this.whiteMoves.length) {
            this.stuckColor = PIECE_COLOR_WHITE;
        } else if (Piece.isBlackColor(this.currentTurn) && !this.blackMoves.length) {
            this.stuckColor = PIECE_COLOR_BLACK;
        }
    }

    calcCanMove(option: OptionsType) {
        this.init(option);
        this.generateCanMoves();
        this.cleanPieceNoMove();
        let moves: PieceIndex[] = [];
        if (this.genCanMove) {
            moves = Piece.isWhiteColor(this.currentTurn) ? this.whiteMoves : this.blackMoves;
        }
        let anotherMoves: PieceIndex[] = [];
        if (this.genCanMoveForAnother) {
            anotherMoves = Piece.isBlackColor(this.currentTurn) ? this.whiteMoves : this.blackMoves;
        }
        return {
            moves,
            anotherMoves,
        };
    }

    calcState(option: OptionsType) {
        this.init(option);
        this.generateCanMoves();
        this.cleanPieceNoMove();

        this.checkIfKingInDanger();
        this.genWinLost();
        this.getStuck();
        return {
            blackKingInDanger: this.blackKingInDanger,
            whiteKingInDanger: this.whiteKingInDanger,
            blackKingWillInDanger: this.blackKingWillInDanger,
            whiteKingWillInDanger: this.whiteKingWillInDanger,
            winColor: this.winColor,
            stuckColor: this.stuckColor,
            blackCountable: boardHelper.checkCountable(
                PIECE_COLOR_BLACK,
                this.piecesString
            ),
            whiteCountable: boardHelper.checkCountable(
                PIECE_COLOR_WHITE,
                this.piecesString
            ),
        };
    }

    calCount(option: CalCountPropsType) {
        return {
            countingBlack: boardHelper.checkCount(
                PIECE_COLOR_BLACK,
                option.piecesString, option.force
            ),
            countingWhite: boardHelper.checkCount(
                PIECE_COLOR_WHITE,
                option.piecesString, option.force
            ),
        };
    }
}

export default new MoveHelper();